// Mirrors @testing-library/react: a SCOPED package with NO exports map, typed
// only via the classic top-level `types` field. `screen`/`fireEvent` are
// re-exported from a DIFFERENT package (@testing-library/dom) via a
// non-relative `export *`, which the resolver never follows cross-package —
// so the surface degrades to Dynamic (info), never a false High.
export * from '@testing-library/dom';

export declare function render(ui: unknown, options?: unknown): unknown;
